#!/usr/bin/env node
/**
 * Replays an iyzico Checkout Form callback against staging.
 * Use only a token generated by a staging/sandbox checkout. No secrets are read or stored.
 */
const args = Object.fromEntries(process.argv.slice(2).map((item) => {
  const [key, ...rest] = item.replace(/^--/, '').split('=');
  return [key, rest.join('=')];
}));
const endpoint = args.endpoint || process.env.IYZICO_CALLBACK_URL;
const token = args.token || process.env.IYZICO_TEST_TOKEN;
const repeat = Math.max(1, Math.min(5, Number(args.repeat || 1)));
if (!endpoint || !/^https?:\/\//i.test(endpoint)) throw new Error('--endpoint=https://staging.example/api/iyzico-callback is required.');
if (!token || token.includes('{{')) throw new Error('--token=<sandbox checkout token> is required.');
for (let index = 1; index <= repeat; index += 1) {
  const response = await fetch(endpoint, {
    method: 'POST',
    redirect: 'manual',
    headers: { 'content-type': 'application/x-www-form-urlencoded' },
    body: new URLSearchParams({ token }).toString(),
    signal: AbortSignal.timeout(15000)
  });
  console.log(JSON.stringify({
    attempt: index,
    status: response.status,
    location: response.headers.get('location'),
    expected: '302/303 redirect to payment success or failure page'
  }));
}
